<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Conway's Game of Life</title>
<style>
  :root {
    color-scheme: dark;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    background: radial-gradient(circle at 50% 20%, #1a1f2e 0%, #0b0e17 70%);
    color: #e8ecf6;
    font-family: 'Segoe UI', system-ui, sans-serif;
    gap: 18px;
    padding: 24px;
  }
  h1 {
    margin: 0;
    font-size: 1.6rem;
    letter-spacing: 0.06em;
    background: linear-gradient(90deg, #7ee8fa, #b98cf5, #ff9de2);
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
  }
  #gridWrap {
    padding: 10px;
    border-radius: 16px;
    background: #131826;
    box-shadow: 0 0 0 1px #262c40, 0 20px 60px rgba(0,0,0,0.5), inset 0 0 30px rgba(126,232,250,0.05);
  }
  #life {
    display: block;
    border-radius: 10px;
    background: #0d1120;
    cursor: crosshair;
    touch-action: none;
    image-rendering: pixelated;
  }
  #controls {
    display: flex;
    gap: 12px;
    flex-wrap: wrap;
    justify-content: center;
  }
  button {
    appearance: none;
    border: 1px solid #2c3550;
    background: linear-gradient(180deg, #1c2338, #141a2b);
    color: #e8ecf6;
    padding: 10px 18px;
    border-radius: 10px;
    font-size: 0.95rem;
    font-weight: 600;
    letter-spacing: 0.02em;
    cursor: pointer;
    transition: transform 0.12s ease, box-shadow 0.12s ease, background 0.12s ease;
  }
  button:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 18px rgba(126,232,250,0.15);
    background: linear-gradient(180deg, #232c47, #1a2138);
  }
  button:active {
    transform: translateY(0);
  }
  #play.active {
    background: linear-gradient(180deg, #2b6f5c, #1c4e40);
    border-color: #3ea885;
  }
  #status {
    font-size: 0.85rem;
    color: #8b93ab;
  }
</style>
</head>
<body>
  <h1>Conway&rsquo;s Game of Life</h1>
  <div id="gridWrap">
    <canvas id="life" width="480" height="480"></canvas>
  </div>
  <div id="controls">
    <button id="step">Step ▶</button>
    <button id="play">Play ▷</button>
    <button id="random">Random 🎲</button>
    <button id="clear">Clear ✖</button>
  </div>
  <div id="status">generation 0</div>

<script>
(function() {
  const W = 50, H = 50;
  const canvas = document.getElementById('life');
  const ctx = canvas.getContext('2d');

  const cssSize = 480;
  canvas.style.width = cssSize + 'px';
  canvas.style.height = cssSize + 'px';
  const dpr = window.devicePixelRatio || 1;
  canvas.width = cssSize * dpr;
  canvas.height = cssSize * dpr;
  ctx.scale(dpr, dpr);

  const cellSize = cssSize / W;

  let grid = new Uint8Array(W * H);
  let generation = 0;

  function idx(x, y) { return y * W + x; }
  function inBounds(x, y) { return x >= 0 && x < W && y >= 0 && y < H; }

  function get(x, y) {
    if (!inBounds(x, y)) return 0;
    return grid[idx(x, y)];
  }

  function set(x, y, v) {
    if (!inBounds(x, y)) return;
    grid[idx(x, y)] = v ? 1 : 0;
    draw();
  }

  function countNeighbors(x, y) {
    let n = 0;
    for (let dy = -1; dy <= 1; dy++) {
      for (let dx = -1; dx <= 1; dx++) {
        if (dx === 0 && dy === 0) continue;
        n += get(x + dx, y + dy);
      }
    }
    return n;
  }

  function step() {
    const next = new Uint8Array(W * H);
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        const alive = grid[idx(x, y)];
        const n = countNeighbors(x, y);
        let nextAlive = 0;
        if (alive) {
          nextAlive = (n === 2 || n === 3) ? 1 : 0;
        } else {
          nextAlive = (n === 3) ? 1 : 0;
        }
        next[idx(x, y)] = nextAlive;
      }
    }
    grid = next;
    generation++;
    draw();
    updateStatus();
  }

  function clear() {
    grid = new Uint8Array(W * H);
    generation = 0;
    draw();
    updateStatus();
  }

  function randomize() {
    for (let i = 0; i < grid.length; i++) {
      grid[i] = Math.random() < 0.25 ? 1 : 0;
    }
    generation = 0;
    draw();
    updateStatus();
  }

  function draw() {
    ctx.fillStyle = '#0d1120';
    ctx.fillRect(0, 0, cssSize, cssSize);

    ctx.strokeStyle = 'rgba(126,232,250,0.06)';
    ctx.lineWidth = 1;
    ctx.beginPath();
    for (let x = 0; x <= W; x++) {
      const px = Math.round(x * cellSize) + 0.5;
      ctx.moveTo(px, 0);
      ctx.lineTo(px, cssSize);
    }
    for (let y = 0; y <= H; y++) {
      const py = Math.round(y * cellSize) + 0.5;
      ctx.moveTo(0, py);
      ctx.lineTo(cssSize, py);
    }
    ctx.stroke();

    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        if (grid[idx(x, y)]) {
          const px = x * cellSize;
          const py = y * cellSize;
          const grad = ctx.createLinearGradient(px, py, px + cellSize, py + cellSize);
          grad.addColorStop(0, '#7ee8fa');
          grad.addColorStop(1, '#b98cf5');
          ctx.fillStyle = grad;
          ctx.fillRect(px + 1, py + 1, cellSize - 2, cellSize - 2);
        }
      }
    }
  }

  function updateStatus() {
    let alive = 0;
    for (let i = 0; i < grid.length; i++) alive += grid[i];
    document.getElementById('status').textContent =
      `generation ${generation} · ${alive} alive`;
  }

  function canvasToCell(clientX, clientY) {
    const rect = canvas.getBoundingClientRect();
    const x = Math.floor((clientX - rect.left) / (rect.width / W));
    const y = Math.floor((clientY - rect.top) / (rect.height / H));
    return { x, y };
  }

  let painting = false;
  let paintValue = 1;

  function paintAt(clientX, clientY) {
    const { x, y } = canvasToCell(clientX, clientY);
    if (inBounds(x, y)) {
      set(x, y, paintValue);
      updateStatus();
    }
  }

  canvas.addEventListener('pointerdown', (e) => {
    painting = true;
    const { x, y } = canvasToCell(e.clientX, e.clientY);
    if (inBounds(x, y)) {
      paintValue = get(x, y) ? 0 : 1;
      set(x, y, paintValue);
      updateStatus();
    }
    canvas.setPointerCapture(e.pointerId);
  });
  canvas.addEventListener('pointermove', (e) => {
    if (painting) paintAt(e.clientX, e.clientY);
  });
  canvas.addEventListener('pointerup', () => { painting = false; });
  canvas.addEventListener('pointerleave', () => { painting = false; });

  let playing = false;
  let playHandle = null;
  const playBtn = document.getElementById('play');

  function togglePlay() {
    playing = !playing;
    if (playing) {
      playBtn.textContent = 'Pause ❚❚';
      playBtn.classList.add('active');
      playHandle = setInterval(step, 150);
    } else {
      playBtn.textContent = 'Play ▷';
      playBtn.classList.remove('active');
      clearInterval(playHandle);
    }
  }

  document.getElementById('step').addEventListener('click', step);
  document.getElementById('play').addEventListener('click', togglePlay);
  document.getElementById('random').addEventListener('click', () => {
    if (playing) togglePlay();
    randomize();
  });
  document.getElementById('clear').addEventListener('click', () => {
    if (playing) togglePlay();
    clear();
  });

  draw();
  updateStatus();

  window.life = {
    w: W,
    h: H,
    get,
    set,
    step,
    clear,
  };
})();
</script>
</body>
</html>
